import React, { useState, useEffect } from 'react';
import { api } from '../utils/api';

const inputStyle = {
  width: '100%', padding: '12px 16px', borderRadius: '8px',
  border: '1px solid #eaebef', outline: 'none', fontSize: '14px', background: '#f4f5f9'
};
const labelStyle = {
  fontSize: '12px', fontWeight: 700, color: '#8a94a6', display: 'block',
  marginBottom: '6px', textTransform: 'uppercase'
};

export default function OrdonnanceModal({ patient, onClose }) {
  const [ordonnances, setOrdonnances] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({
    date: new Date().toISOString().slice(0, 10),
    medecin: '',
    medicaments: [{ nom: '', dosage: '', duree: '', instructions: '' }],
    observations: '',
    diagnostic: ''
  });

  const load = async () => {
    setLoading(true);
    try {
      const data = await api.getOrdonnances(patient.id);
      setOrdonnances(data);
    } catch {
      setOrdonnances([]);
    }
    setLoading(false);
  };

  useEffect(() => { load(); }, [patient.id]);

  const addMedicament = () => {
    setForm(f => ({
      ...f,
      medicaments: [...f.medicaments, { nom: '', dosage: '', duree: '', instructions: '' }]
    }));
  };

  const removeMedicament = (idx) => {
    setForm(f => ({ ...f, medicaments: f.medicaments.filter((_, i) => i !== idx) }));
  };

  const updateMedicament = (idx, field, value) => {
    setForm(f => {
      const meds = [...f.medicaments];
      meds[idx] = { ...meds[idx], [field]: value };
      return { ...f, medicaments: meds };
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await api.createOrdonnance({ ...form, patientId: patient.id });
      await load();
      setShowForm(false);
      setForm({
        date: new Date().toISOString().slice(0, 10),
        medecin: '',
        medicaments: [{ nom: '', dosage: '', duree: '', instructions: '' }],
        observations: '',
        diagnostic: ''
      });
    } catch (err) {
      alert('Erreur lors de l\'enregistrement');
    }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Supprimer cette ordonnance ?')) {
      await api.deleteOrdonnance(id);
      load();
    }
  };

  const printOrdonnance = (ord) => {
    const age = patient.dateNaissance
      ? Math.floor((Date.now() - new Date(patient.dateNaissance)) / (1000 * 60 * 60 * 24 * 365.25)) + ' ans'
      : '—';
    const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8"/>
  <title>Ordonnance – ${patient.prenom} ${patient.nom}</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@400;500;600;700&display=swap');
    * { margin:0; padding:0; box-sizing:border-box; }
    body { font-family:'DM Sans',sans-serif; color:#1d2129; background:#fff; padding:0; }
    .page { width:210mm; min-height:297mm; padding:20mm 22mm; margin:0 auto; background:white; }
    .header { display:flex; justify-content:space-between; align-items:flex-start; border-bottom:2px solid #0056ff; padding-bottom:12px; margin-bottom:20px; }
    .header-left h1 { font-family:'Syne',sans-serif; color:#0056ff; font-size:24px; font-weight:800; }
    .header-left p { color:#8a94a6; font-size:12px; margin-top:2px; }
    .header-right { text-align:right; }
    .header-right .date { font-weight:700; font-size:14px; color:#1d2129; }
    .header-right .num { font-size:11px; color:#8a94a6; font-family:monospace; }
    .section { margin-bottom:16px; }
    .section-title { font-family:'Syne',sans-serif; font-size:11px; font-weight:800; color:#0056ff; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px; padding-bottom:4px; border-bottom:1px solid #eaebef; }
    .patient-box { background:#f4f7fe; border-radius:8px; padding:12px 16px; display:flex; gap:24px; margin-bottom:16px; }
    .patient-info strong { font-size:16px; font-weight:800; }
    .patient-info span { font-size:12px; color:#8a94a6; display:block; margin-top:2px; }
    .diag-box { background:#fff8e1; border-left:3px solid #f59e0b; padding:10px 14px; border-radius:4px; margin-bottom:16px; font-style:italic; font-size:13px; }
    .med-table { width:100%; border-collapse:collapse; font-size:13px; }
    .med-table thead tr { background:#0056ff; color:white; }
    .med-table th { padding:8px 12px; text-align:left; font-weight:700; font-size:11px; text-transform:uppercase; letter-spacing:0.5px; }
    .med-table td { padding:10px 12px; border-bottom:1px solid #eaebef; vertical-align:top; }
    .med-table tbody tr:nth-child(even) { background:#f9fafb; }
    .med-name { font-weight:700; color:#1d2129; }
    .med-dosage { font-weight:600; color:#0056ff; font-size:12px; }
    .obs-box { background:#f4f5f9; padding:12px 16px; border-radius:8px; font-size:13px; color:#1d2129; margin-top:12px; }
    .footer { margin-top:40px; display:flex; justify-content:flex-end; }
    .signature-box { text-align:center; }
    .signature-line { width:180px; border-top:1px solid #1d2129; margin:48px auto 6px; }
    .signature-label { font-size:12px; color:#8a94a6; }
    .stamp { border:2px dashed #0056ff; border-radius:8px; padding:12px 20px; min-width:150px; text-align:center; font-size:11px; color:#0056ff; font-weight:700; }
    @media print { .page { padding:15mm 18mm; } }
  </style>
</head>
<body>
<div class="page">
  <div class="header">
    <div class="header-left">
      <h1>💊 ORDONNANCE MÉDICALE</h1>
      <p>Service de Médecine Préventive — SEMEP</p>
    </div>
    <div class="header-right">
      <div class="date">${new Date(ord.date).toLocaleDateString('fr-FR', { day:'2-digit', month:'long', year:'numeric' })}</div>
      <div class="num">Réf : ORD-${ord.id?.slice(0,8).toUpperCase()}</div>
    </div>
  </div>

  <div class="patient-box">
    <div class="patient-info">
      <strong>${patient.prenom} ${patient.nom}</strong>
      <span>Âge : ${age} | Sexe : ${patient.sexe === 'M' ? 'Masculin' : 'Féminin'} | Groupe sanguin : ${patient.groupeSanguin || '—'}</span>
      <span>Adresse : ${patient.adresse || '—'}</span>
    </div>
    <div class="patient-info" style="margin-left:auto; text-align:right;">
      <strong>N° Dossier</strong>
      <span style="font-family:monospace; font-size:11px;">${patient.id}</span>
    </div>
  </div>

  ${ord.diagnostic ? `
  <div class="section">
    <div class="section-title">🩺 Diagnostic / Motif</div>
    <div class="diag-box">${ord.diagnostic}</div>
  </div>` : ''}

  <div class="section">
    <div class="section-title">💊 Médicaments Prescrits</div>
    <table class="med-table">
      <thead>
        <tr>
          <th>#</th>
          <th>Médicament</th>
          <th>Dosage / Posologie</th>
          <th>Durée</th>
          <th>Instructions Spéciales</th>
        </tr>
      </thead>
      <tbody>
        ${(ord.medicaments || []).map((m, i) => `
        <tr>
          <td style="font-weight:800; color:#0056ff;">${i + 1}</td>
          <td><div class="med-name">${m.nom || '—'}</div></td>
          <td><div class="med-dosage">${m.dosage || '—'}</div></td>
          <td>${m.duree || '—'}</td>
          <td style="font-size:12px; font-style:italic; color:#8a94a6;">${m.instructions || '—'}</td>
        </tr>`).join('')}
      </tbody>
    </table>
  </div>

  ${ord.observations ? `
  <div class="section">
    <div class="section-title">📝 Observations</div>
    <div class="obs-box">${ord.observations}</div>
  </div>` : ''}

  <div class="footer">
    <div class="signature-box">
      <div class="stamp">CACHET DU MÉDECIN</div>
      <div class="signature-line"></div>
      <div class="signature-label">Dr. ${ord.medecin || '________________________'}</div>
    </div>
  </div>
</div>
<script>window.onload = () => { window.print(); window.onafterprint = () => window.close(); }</script>
</body>
</html>`;
    const w = window.open('', '_blank', 'width=900,height=700');
    w.document.write(html);
    w.document.close();
  };

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(29,33,41,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1100 }} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: 'white', borderRadius: '20px', padding: '32px', width: '100%', maxWidth: '700px', boxShadow: '0 20px 60px rgba(0,0,0,0.15)', maxHeight: '90vh', overflowY: 'auto' }}>

        {/* HEADER */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '24px' }}>
          <div>
            <h2 style={{ fontFamily: 'Syne', fontSize: '20px', fontWeight: 800, color: '#1d2129', marginBottom: '4px' }}>
              💊 Ordonnances
            </h2>
            <p style={{ fontSize: '13px', color: '#8a94a6' }}>
              {patient.prenom} {patient.nom} — {ordonnances.length} ordonnance(s)
            </p>
          </div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setShowForm(f => !f)} style={{
              background: showForm ? '#f4f5f9' : '#0056ff', color: showForm ? '#8a94a6' : 'white',
              border: 'none', padding: '10px 18px', borderRadius: '50px', fontWeight: 700, 
              cursor: 'pointer', fontSize: '13px', display: 'flex', alignItems: 'center', gap: '6px'
            }}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                {showForm ? <><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></> : <><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></>}
              </svg>
              {showForm ? 'Annuler' : 'Nouvelle Ordonnance'}
            </button>
            <button onClick={onClose} style={{ background: '#f4f5f9', border: 'none', borderRadius: '50%', width: '36px', height: '36px', cursor: 'pointer', color: '#8a94a6', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
            </button>
          </div>
        </div>

        {/* FORMULAIRE */}
        {showForm && (
          <form onSubmit={handleSubmit} style={{ background: '#f9faff', border: '1px solid #d4e3ff', borderRadius: '16px', padding: '24px', marginBottom: '24px' }}>
            <h3 style={{ fontSize: '14px', fontWeight: 800, color: '#0056ff', marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              ✍️ Nouvelle ordonnance
            </h3>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '16px' }}>
              <div>
                <label style={labelStyle}>Date</label>
                <input type="date" value={form.date} onChange={e => setForm(f => ({ ...f, date: e.target.value }))} style={inputStyle} />
              </div>
              <div>
                <label style={labelStyle}>Médecin</label>
                <input value={form.medecin} onChange={e => setForm(f => ({ ...f, medecin: e.target.value }))} placeholder="Dr. Nom Prénom" style={inputStyle} />
              </div>
            </div>

            <div style={{ marginBottom: '16px' }}>
              <label style={labelStyle}>Diagnostic / Motif (facultatif)</label>
              <input value={form.diagnostic} onChange={e => setForm(f => ({ ...f, diagnostic: e.target.value }))} placeholder="Ex: Infection respiratoire, Hypertension..." style={inputStyle} />
            </div>

            {/* MÉDICAMENTS */}
            <div style={{ marginBottom: '16px' }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
                <label style={{ ...labelStyle, marginBottom: 0 }}>Médicaments</label>
                <button type="button" onClick={addMedicament} style={{ background: '#ebf2ff', color: '#0056ff', border: 'none', borderRadius: '50px', padding: '4px 12px', fontSize: '12px', fontWeight: 700, cursor: 'pointer' }}>
                  + Ajouter
                </button>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {form.medicaments.map((m, idx) => (
                  <div key={idx} style={{ background: 'white', border: '1px solid #eaebef', borderRadius: '12px', padding: '14px' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                      <span style={{ fontSize: '12px', fontWeight: 800, color: '#0056ff' }}>Médicament {idx + 1}</span>
                      {form.medicaments.length > 1 && (
                        <button type="button" onClick={() => removeMedicament(idx)} style={{ background: '#fce7f3', color: '#ec4899', border: 'none', borderRadius: '4px', padding: '2px 8px', fontSize: '11px', cursor: 'pointer' }}>
                          Supprimer
                        </button>
                      )}
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr', gap: '10px' }}>
                      <div>
                        <label style={{ ...labelStyle, fontSize: '10px' }}>Nom du médicament</label>
                        <input value={m.nom} onChange={e => updateMedicament(idx, 'nom', e.target.value)} placeholder="Amoxicilline 500mg..." style={{ ...inputStyle, padding: '8px 12px', fontSize: '13px' }} />
                      </div>
                      <div>
                        <label style={{ ...labelStyle, fontSize: '10px' }}>Dosage / Posologie</label>
                        <input value={m.dosage} onChange={e => updateMedicament(idx, 'dosage', e.target.value)} placeholder="3x/jour" style={{ ...inputStyle, padding: '8px 12px', fontSize: '13px' }} />
                      </div>
                      <div>
                        <label style={{ ...labelStyle, fontSize: '10px' }}>Durée</label>
                        <input value={m.duree} onChange={e => updateMedicament(idx, 'duree', e.target.value)} placeholder="7 jours" style={{ ...inputStyle, padding: '8px 12px', fontSize: '13px' }} />
                      </div>
                    </div>
                    <div style={{ marginTop: '8px' }}>
                      <label style={{ ...labelStyle, fontSize: '10px' }}>Instructions spéciales (facultatif)</label>
                      <input value={m.instructions} onChange={e => updateMedicament(idx, 'instructions', e.target.value)} placeholder="À prendre avec les repas, éviter l'alcool..." style={{ ...inputStyle, padding: '8px 12px', fontSize: '13px' }} />
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{ marginBottom: '16px' }}>
              <label style={labelStyle}>Observations complémentaires (facultatif)</label>
              <textarea value={form.observations} onChange={e => setForm(f => ({ ...f, observations: e.target.value }))} placeholder="Repos conseillé, prochain rendez-vous..." rows={3} style={{ ...inputStyle, resize: 'vertical', lineHeight: '1.5' }} />
            </div>

            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '10px' }}>
              <button type="button" onClick={() => setShowForm(false)} style={{ padding: '10px 20px', borderRadius: '50px', border: '1px solid #eaebef', background: 'white', fontWeight: 700, cursor: 'pointer', color: '#8a94a6', fontSize: '13px' }}>Annuler</button>
              <button type="submit" disabled={saving} style={{ padding: '10px 20px', borderRadius: '50px', border: 'none', background: '#0056ff', fontWeight: 700, cursor: 'pointer', color: 'white', fontSize: '13px' }}>
                {saving ? 'Enregistrement...' : '💾 Enregistrer l\'ordonnance'}
              </button>
            </div>
          </form>
        )}

        {/* LISTE ORDONNANCES */}
        {loading ? (
          <div style={{ textAlign: 'center', padding: '40px', color: '#8a94a6' }}>Chargement...</div>
        ) : ordonnances.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '48px 20px', color: '#8a94a6', background: '#f9fafb', borderRadius: '12px' }}>
            <div style={{ fontSize: '40px', marginBottom: '12px' }}>💊</div>
            <div style={{ fontWeight: 700, fontSize: '15px', marginBottom: '6px' }}>Aucune ordonnance</div>
            <div style={{ fontSize: '13px' }}>Cliquez sur "Nouvelle Ordonnance" pour en créer une.</div>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {ordonnances.map(ord => (
              <div key={ord.id} style={{ border: '1px solid #eaebef', borderRadius: '14px', padding: '16px 20px', background: 'white' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
                  <div>
                    <div style={{ fontWeight: 800, fontSize: '14px', color: '#1d2129' }}>
                      📅 {new Date(ord.date).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' })}
                    </div>
                    {ord.medecin && <div style={{ fontSize: '12px', color: '#8a94a6', marginTop: '2px' }}>Dr. {ord.medecin}</div>}
                    {ord.diagnostic && (
                      <div style={{ fontSize: '12px', background: '#fff8e1', color: '#92400e', padding: '3px 10px', borderRadius: '50px', display: 'inline-block', marginTop: '6px', fontWeight: 600 }}>
                        🩺 {ord.diagnostic}
                      </div>
                    )}
                  </div>
                  <div style={{ display: 'flex', gap: '6px' }}>
                    <button onClick={() => printOrdonnance(ord)} style={{ background: '#ebf2ff', color: '#0056ff', border: 'none', borderRadius: '8px', padding: '6px 12px', cursor: 'pointer', fontWeight: 700, fontSize: '12px', display: 'flex', alignItems: 'center', gap: '4px' }}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="6 9 6 2 18 2 18 9"/><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"/><rect x="6" y="14" width="12" height="8"/></svg>
                      Imprimer
                    </button>
                    <button onClick={() => handleDelete(ord.id)} style={{ background: '#fce7f3', color: '#ec4899', border: 'none', borderRadius: '8px', padding: '6px 10px', cursor: 'pointer' }}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                    </button>
                  </div>
                </div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                  {(ord.medicaments || []).filter(m => m.nom).map((m, i) => (
                    <span key={i} style={{ background: '#f4f5f9', color: '#1d2129', padding: '4px 12px', borderRadius: '50px', fontSize: '12px', fontWeight: 600 }}>
                      💊 {m.nom} {m.dosage && `— ${m.dosage}`}
                    </span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
